SELECT
h.*,
u.real_name AS landlord_name,
u.phone AS landlord_phone
FROM houses h
LEFT JOIN users u ON h.landlord_id = u.id

    
    
        AND h.status = 1
    
    
        AND h.status = #{query.status}
    
    
        AND h.landlord_id = #{query.landlordId}
    
    
        AND h.city = #{query.city}
    
    
        AND h.district = #{query.district}
    
    
        AND h.house_type = #{query.houseType}
    
    
        AND h.rent_price >= #{query.minPrice}
    
    
        AND h.rent_price <= #{query.maxPrice}
    
    
        AND (h.title LIKE CONCAT('%', #{query.keyword}, '%')
        OR h.address LIKE CONCAT('%', #{query.keyword}, '%'))
    

ORDER BY

    
        ${query.sortField} ${query.sortOrder}
    
    
        h.created_at DESC
    

LIMIT #{query.limit} OFFSET #{query.limit * (query.page - 1)}

SELECT COUNT(*)
FROM houses h

    
    
        AND h.status = 1
    
    
        AND h.status = #{query.status}
    
    
        AND h.landlord_id = #{query.landlordId}
    
    
        AND h.city = #{query.city}
    
    
        AND h.district = #{query.district}
    
    
        AND h.house_type = #{query.houseType}
    
    
        AND h.rent_price >= #{query.minPrice}
    
    
        AND h.rent_price <= #{query.maxPrice}
    
    
        AND (h.title LIKE CONCAT('%', #{query.keyword}, '%')
        OR h.address LIKE CONCAT('%', #{query.keyword}, '%'))
